%[text] # 例4.3（ガウス関数のFT）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example04_03"; % mfilename
%%
%[text] 
syms t sigma pi_real
assume(pi_real','real')
assume(pi_real','positive')
assume(sigma,'real')
assume(sigma,'positive')
pi_real = sym(pi) %[output:7245df6a]

g = 1/(sqrt(2*pi_real)*sigma)*exp(-(1/2)*(t/sigma)^2) %[output:40f423ba]

G = fourier(g) %[output:2c271292]

G = subs(G,sigma,2) %[output:6d94e7bf]
fplot(G) %[output:0449776f]
